def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an athlete (or related entities) into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build entity relationships to create connected sentences
    entity_info = {}
    for triple in triples:
        subj = triple.subject
        pred = triple.predicate.lower()
        obj = triple.object

        if subj not in entity_info:
            entity_info[subj] = []
        entity_info[subj].append((pred, obj))

    # Find main subject (most triples or athlete-related)
    main_subject = max(entity_info.keys(), key=lambda s: len(entity_info[s]))
    related_entities = {obj for subj, preds in entity_info.items() for pred, obj in preds if subj != main_subject}

    # Build connected clauses with better flow
    clauses = []

    # Process main subject first with most natural phrasing
    main_clauses = []
    for pred, obj in entity_info.get(main_subject, []):
        if pred == "birthDate":
            main_clauses.append(f"was born on {obj}")
        elif pred == "birthYear":
            main_clauses.append(f"was born in {obj}")
        elif pred == "birthPlace":
            main_clauses.append(f"was born in {obj}")
        elif pred == "height":
            main_clauses.append(f"measures {obj} in height")
        elif pred == "weight":
            main_clauses.append(f"weighs {obj}")
        elif pred == "league":
            main_clauses.append(f"plays in {obj}")
        elif pred == "club":
            main_clauses.append(f"plays for {obj}")
        elif pred == "currentclub":
            main_clauses.append(f"currently plays for {obj}")
        elif pred == "position":
            main_clauses.append(f"plays as a {obj}")
        elif pred == "manager":
            main_clauses.append(f"is managed by {obj}")
        elif pred == "coach":
            main_clauses.append(f"is coached by {obj}")
        elif pred == "owner":
            main_clauses.append(f"is owned by {obj}")
        elif pred == "city":
            main_clauses.append(f"is based in {obj}")
        elif pred == "country":
            main_clauses.append(f"comes from {obj}")
        elif pred == "isPartOf":
            main_clauses.append(f"is part of {obj}")
        elif pred == "season":
            main_clauses.append(f"participated in the {obj} season")
        elif pred == "foundingDate":
            main_clauses.append(f"was founded on {obj}")
        elif pred == "utcOffset":
            main_clauses.append(f"has a UTC offset of {obj}")
        elif pred == "timeZone":
            main_clauses.append(f"is in the {obj} time zone")
        elif pred == "areaTotal":
            main_clauses.append(f"covers an area of {obj}")
        elif pred == "demonym":
            main_clauses.append(f"The people of {main_subject} are called {obj}")
        elif pred == "language":
            main_clauses.append(f"The official language is {obj}")
        elif pred == "officialLanguage":
            main_clauses.append(f"The official language is {obj}")
        elif pred == "anthem":
            main_clauses.append(f"The national anthem is {obj}")
        elif pred == "leader":
            main_clauses.append(f"The leader is {obj}")
        elif pred == "leaderTitle":
            main_clauses.append(f"The leader title is {obj}")
        elif pred == "mostChampions":
            main_clauses.append(f"The team with the most championships is {obj}")
        elif pred == "currency":
            main_clauses.append(f"The currency is {obj}")
        elif pred == "demographic":
            main_clauses.append(f"has a demographic of {obj}")
        else:
            main_clauses.append(f"{pred}: {obj}")

    # Join main clauses into a readable sentence
    if main_clauses:
        if len(main_clauses) == 1:
            sentence = f"{main_subject} {main_clauses[0]}."
        else:
            sentence = f"{main_subject} {'; '.join(main_clauses[:-1])}; and {main_clauses[-1]}."
